#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    int da = ((int*)a)[0];
    int db = ((int*)b)[0];
    return db - da; // descending by distance
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M, X; scanf("%d %d %d", &N, &M, &X);
        int *dist = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++) scanf("%d", &dist[i]);
        int *qual = (int*)malloc(N*sizeof(int));
        int qcnt = 0;
        int (*rem)[2] = malloc(N * sizeof *rem);
        int rcnt = 0;
        for(int i=1;i<=N;i++){
            if(dist[i] >= M) qual[qcnt++] = i;
            else { rem[rcnt][0] = dist[i]; rem[rcnt][1] = i; rcnt++; }
        }
        if(qcnt < X){
            qsort(rem, rcnt, sizeof *rem, cmp_desc);
            int need = X - qcnt;
            for(int i=0;i<need;i++) qual[qcnt++] = rem[i][1];
        }
        // sort IDs ascending (simple insertion sort, N ≤ 30)
        for(int i=1;i<qcnt;i++){
            int key = qual[i];
            int j=i-1;
            while(j>=0 && qual[j]>key){qual[j+1]=qual[j];j--;}
            qual[j+1]=key;
        }
        printf("%d", qcnt);
        for(int i=0;i<qcnt;i++) printf(" %d", qual[i]);
        if(T) printf("\n");
        free(dist); free(qual); free(rem);
    }
    return 0;
}

