import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int X = fs.nextInt();
            int[] A = new int[N+1];
            for (int i = 1; i <= N; i++) A[i] = fs.nextInt();
            List<Integer> qualified = new ArrayList<>();
            List<int[]> others = new ArrayList<>();
            for (int i = 1; i <= N; i++) {
                if (A[i] >= M) qualified.add(i);
                else others.add(new int[]{A[i], i});
            }
            if (qualified.size() < X) {
                others.sort((a,b) -> Integer.compare(b[0], a[0])); // descending distance
                int need = X - qualified.size();
                for (int i = 0; i < need; i++) qualified.add(others.get(i)[1]);
            }
            Collections.sort(qualified);
            sb.append(qualified.size());
            for (int id : qualified) sb.append(' ').append(id);
            if (T > 0) sb.append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for competitive programming
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

