#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); X = int(next(it))
        A = [0] + [int(next(it)) for _ in range(N)]
        qualified = []
        others = []
        for i in range(1, N+1):
            if A[i] >= M:
                qualified.append(i)
            else:
                others.append((A[i], i))
        if len(qualified) < X:
            others.sort(key=lambda x: -x[0])
            need = X - len(qualified)
            qualified.extend(i for _, i in others[:need])
        qualified.sort()
        out_lines.append(str(len(qualified)) + ' ' + ' '.join(map(str, qualified)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

